#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <float.h>
#include <math.h>
#include <omp.h>

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static void tvsub(struct timeval *end, struct timeval *beg, struct timeval *res) {
  res->tv_sec = end->tv_sec - beg->tv_sec;
  res->tv_usec = end->tv_usec - beg->tv_usec;
  if (res->tv_usec < 0) {
    res->tv_sec--;
    res->tv_usec += 1000000;
  }
}
#endif

#define min(a, b) a > b ? b : a
#define ceilDiv(a, b) (a + b - 1) / b
#define print(x) printf(#x ": %lu\n", (unsigned long)x)
#define DEBUG 0

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53
#define LATITUDE_POS 28
#define OPEN 10000

typedef struct latLong {
  float lat;
  float lng;
} LatLong;

typedef struct record {
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename, Record **records_out, LatLong **locations_out);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

int main(int argc, char *argv[]) {
  int i = 0;
  float lat, lng;
  int quiet = 0, timing = 0, platform = 0, device = 0;

  Record *records = NULL;
  LatLong *locations = NULL;
  char filename[100];
  int resultsCount = 10;

  if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                       &quiet, &timing, &platform, &device)) {
    printUsage();
    return 0;
  }

  int numRecords = loadData(filename, &records, &locations);
  if (resultsCount > numRecords) resultsCount = numRecords;

  float *distances = (float *)malloc(sizeof(float) * (size_t)numRecords);
  if (!distances) {
    fprintf(stderr, "Error allocating distances.\n");
    free(records);
    free(locations);
    return 1;
  }

#ifdef TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

#pragma omp parallel for
  for (i = 0; i < numRecords; i++) {
    float dlat = lat - locations[i].lat;
    float dlng = lng - locations[i].lng;
    distances[i] = sqrtf(dlat * dlat + dlng * dlng);
  }

#ifdef TIMING
  gettimeofday(&tv_kernel_end, NULL);
  tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
  kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  findLowest(records, distances, numRecords, resultsCount);

  if (!quiet)
    for (i = 0; i < resultsCount; i++) {
      printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
    }

  free(distances);
  free(records);
  free(locations);

#ifdef TIMING
  printf("Exec: %f\n", kernel_time);
#endif

  return 0;
}

int loadData(char *filename, Record **records_out, LatLong **locations_out) {
  FILE *flist, *fp;
  int i = 0;
  char dbname[64];
  int recNum = 0;

  int capacity = 1024;
  Record *records = (Record *)malloc(sizeof(Record) * (size_t)capacity);
  LatLong *locations = (LatLong *)malloc(sizeof(LatLong) * (size_t)capacity);
  if (!records || !locations) {
    fprintf(stderr, "memory allocation failure\n");
    free(records);
    free(locations);
    exit(1);
  }

  flist = fopen(filename, "r");
  if (!flist) {
    fprintf(stderr, "error opening filelist\n");
    free(records);
    free(locations);
    exit(1);
  }

  while (!feof(flist)) {
    if (fscanf(flist, "%s\n", dbname) != 1) {
      fprintf(stderr, "error reading filelist\n");
      free(records);
      free(locations);
      fclose(flist);
      exit(0);
    }
    fp = fopen(dbname, "r");
    if (!fp) {
      printf("error opening a db\n");
      free(records);
      free(locations);
      fclose(flist);
      exit(1);
    }

    while (!feof(fp)) {
      Record record;
      LatLong latLong;

      if (fgets(record.recString, 49, fp) == NULL) break;
      fgetc(fp);
      if (feof(fp)) break;

      char substr[6];

      for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
      substr[5] = '\0';
      latLong.lat = (float)atof(substr);

      for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
      substr[5] = '\0';
      latLong.lng = (float)atof(substr);

      if (recNum >= capacity) {
        capacity *= 2;
        Record *new_records = (Record *)realloc(records, sizeof(Record) * (size_t)capacity);
        LatLong *new_locations = (LatLong *)realloc(locations, sizeof(LatLong) * (size_t)capacity);
        if (!new_records || !new_locations) {
          fprintf(stderr, "memory allocation failure\n");
          free(new_records ? new_records : records);
          free(new_locations ? new_locations : locations);
          fclose(fp);
          fclose(flist);
          exit(1);
        }
        records = new_records;
        locations = new_locations;
      }

      locations[recNum] = latLong;
      records[recNum] = record;
      recNum++;
    }
    fclose(fp);
  }
  fclose(flist);

  *records_out = records;
  *locations_out = locations;
  return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN) {
  int i, j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for (i = 0; i < topN; i++) {
    minLoc = i;
    for (j = i; j < numRecords; j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
  int i;
  if (argc < 2) return 1;
  strncpy(filename, argv[1], 100);
  filename[99] = '\0';
  char flag;

  for (i = 1; i < argc; i++) {
    if (argv[i][0] == '-') {
      flag = argv[i][1];
      switch (flag) {
        case 'r':
          i++;
          *r = atoi(argv[i]);
          break;
        case 'l':
          if (argv[i][2] == 'a') {
            *lat = (float)atof(argv[i + 1]);
          } else {
            *lng = (float)atof(argv[i + 1]);
          }
          i++;
          break;
        case 'h':
          return 1;
        case 'q':
          *q = 1;
          break;
        case 't':
          *t = 1;
          break;
        case 'p':
          i++;
          *p = atoi(argv[i]);
          break;
        case 'd':
          i++;
          *d = atoi(argv[i]);
          break;
      }
    }
  }
  if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
    return 1;
  return 0;
}

